const express = require('express');
const helmet = require('helmet');           // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Headers ---
app.use(helmet());

// --- Body Parsing with Size Limit ---
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// --- Rate Limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // TODO: Add authentication middleware before exposing real user data
  res.json([
    { id: 1, name: 'Alice' },  // Don't expose email without auth
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Must have 4 parameters for Express to treat it as an error handler
app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally, never expose to client
  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'  // Hide details in prod
      : err.message              // Show details in dev
  });
});

// --- Graceful Shutdown ---
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

const shutdown = (signal) => {
  console.log(`${signal} received. Shutting down gracefully...`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000); // Force exit after 10s
};

process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT',  () => shutdown('SIGINT'));

module.exports = app;
```

